let loading = false;
let data = null;
let error = null;

async function fetchData() {
  loading = true;
  error = null;
  showSpinner();

  try {
    const res = await fetch('/api/data');
    if (!res.ok) throw new Error('Failed to load');
    data = await res.json();
    renderData(data);
  } catch (err) {
    error = err.message;
    showError(err.message);
  } finally {
    loading = false;
    hideSpinner();
  }
}

